challenge_result.investigation_instruction:
{
  "plans": [
    {
      "hypothesis_id": "h1",
      "hypothesis_statement": "The S-CSCF (Serving-CSCF) container has terminated unexpectedly, breaking the IMS session control plane and preventing VoNR call setup.",
      "primary_suspect_nf": "scscf",
      "probes": [
        {
          "tool": "get_network_status",
          "args_hint": "Global status, check 'scscf' entry",
          "expected_if_hypothesis_holds": "The container status for 'scscf' will be 'exited' or another non-running state.",
          "falsifying_observation": "The 'scscf' container is in a 'running' state. This would directly contradict the hypothesis that it has terminated."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "icscf",
          "expected_if_hypothesis_holds": "Metrics on the I-CSCF will show failures to forward requests to the S-CSCF (e.g., kamailio dispatcher failures or timeouts).",
          "falsifying_observation": "I-CSCF's forwarding-related metrics are normal, with no errors indicating an inability to reach the S-CSCF. This suggests the upstream component is not seeing a failure."
        },
        {
          "tool": "get_nf_metrics",
          "args_hint": "pyhss",
          "expected_if_hypothesis_holds": "Metrics on the HSS (pyhss) for Diameter Cx requests received from S-CSCF will be zero or have flatlined, as the S-CSCF is down and cannot send them.",
          "falsifying_observation": "The HSS is actively receiving and processing Diameter requests from the S-CSCF. This proves the S-CSCF is up and communicating."
        }
      ],
      "notes": "This plan focuses on verifying the direct state of the S-CSCF container and observing the expected knock-on effects on its immediate upstream (I-CSCF) and downstream (HSS/pyhss) neighbors."
    },
    {
      "hypothesis_id": "h2",
      "hypothesis_statement": "The IMS control plane is partitioned, preventing SIP signaling from reaching the HSS and other call-processing components, as evidenced by the failure of the S-CSCF.",
      "primary_suspect_nf": "scscf",
      "probes": [
        {
          "tool": "measure_rtt",
          "args_hint": "From 'icscf' to 'scscf' IP",
          "expected_if_hypothesis_holds": "100% packet loss or extremely high latency, indicating a network partition.",
          "falsifying_observation": "Clean RTT (<5ms) with 0% packet loss. This would prove that the network path between I-CSCF and S-CSCF is healthy, falsifying the partition hypothesis."
        },
        {
          "tool": "check_process_listeners",
          "args_hint": "scscf",
          "expected_if_hypothesis_holds": "A process is running and listening on the S-CSCF's standard SIP port (e.g., 5060), but is unreachable due to the partition.",
          "falsifying_observation": "No process is listening on the expected ports. This indicates the container has crashed or the service failed to start, which contradicts the 'partition' model and favors a 'component failure' model (like h1)."
        },
        {
          "tool": "measure_rtt",
          "args_hint": "Triangulation probe: from 'icscf' to 'pyhss' IP",
          "expected_if_hypothesis_holds": "Clean RTT to HSS. This would help isolate the partition to be specific to the S-CSCF, rather than a general egress problem from the I-CSCF.",
          "falsifying_observation": "High packet loss. If both paths (to scscf and pyhss) from icscf are failing, it points to a problem with the icscf itself or its local network access, rather than a partition isolating the scscf."
        }
      ],
      "notes": "This plan specifically tests the 'network partition' theory. It uses RTT probes to test connectivity directly and a process check to differentiate a running-but-isolated component from a terminated one, which is the key distinction between h2 and h1."
    }
  ]
}

